xpath.script:

(function() {
    'use strict';

    // Import Owl from the global scope
    const { Component, useState, onMounted, xml, mount } = owl;

        // Load Leaflet CSS
        function loadLeafletCSS() {
            if (!document.getElementById('leaflet-css')) {
                const linkElement = document.createElement('link');
                linkElement.id = 'leaflet-css';
                linkElement.rel = 'stylesheet';
                linkElement.href = 'https://unpkg.com/leaflet@1.9.4/dist/leaflet.css';
                document.head.appendChild(linkElement);
            }
        }

        // Load Leaflet JS
        function loadLeafletJS() {
            return new Promise((resolve) => {
                if (!window.L) {
                    const scriptElement = document.createElement('script');
                    scriptElement.src = 'https://unpkg.com/leaflet@1.9.4/dist/leaflet.js';
                    scriptElement.onload = () => resolve();
                    document.head.appendChild(scriptElement);
                } else {
                    resolve();
                }
            });
        }

        // Define the Owl Component for the map
        class CheckoutMapComponent extends Component {
            static template = xml`
                <div class="checkout-map-wrapper">
                    <div id="checkout-map-container" class="mb-3" style="height: 300px; border-radius: 8px;"></div>

                    <!-- Location details -->
                    <div id="location-details" class="mt-3" t-att-style="state.locationSelected ? '' : 'display: none;'">
                        <p class="mb-1"><strong>Selected Location:</strong></p>
                        <p id="location-address" class="mb-2" t-esc="state.address"></p>
                        <p id="location-coordinates" class="small text-muted" t-esc="state.coordinates"></p>
                    </div>

                    <!-- Controls -->
                    <div class="mt-2">
                        <button type="button" id="get-current-location" class="btn btn-sm btn-outline-secondary" t-on-click="getCurrentLocation">
                            <i class="fa fa-location-arrow me-1"></i> Use My Current Location
                        </button>
                        <small class="text-muted ms-3">
                            <i class="fa fa-info-circle me-1"></i> Drag the marker to pinpoint your exact location
                        </small>
                    </div>
                </div>
            `;

            setup() {
                this.state = useState({
                    latitude: 24.7136,  // Default location (Riyadh)
                    longitude: 46.6753,
                    address: '',
                    coordinates: '',
                    locationSelected: false
                });

                this.map = null;
                this.marker = null;

                onMounted(async () => {
                    // Load Leaflet resources
                    loadLeafletCSS();
                    await loadLeafletJS();

                    // Initialize map
                    this.initializeMap();

                    // Try to get user's current location
                    this.tryGetCurrentLocation();
                });
            }

            initializeMap() {
                const mapContainer = document.getElementById('checkout-map-container');
                if (!mapContainer) return;

                // Create map
                this.map = L.map('checkout-map-container').setView([this.state.latitude, this.state.longitude], 13);

                // Add OpenStreetMap tiles
                L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
                    attribution: '© OpenStreetMap contributors'
                }).addTo(this.map);

                // Add a marker that can be dragged
                this.marker = L.marker([this.state.latitude, this.state.longitude], {
                    draggable: true
                }).addTo(this.map);

                // Update location when marker is dragged
                this.marker.on('dragend', () => {
                    const position = this.marker.getLatLng();
                    this.updateLocationData(position.lat, position.lng);
                    this.reverseGeocode(position.lat, position.lng);
                });
            }

            getCurrentLocation() {
                if (navigator.geolocation) {
                    navigator.geolocation.getCurrentPosition(
                        (position) => {
                            const latitude = position.coords.latitude;
                            const longitude = position.coords.longitude;
                            this.map.setView([latitude, longitude], 15);
                            this.marker.setLatLng([latitude, longitude]);
                            this.updateLocationData(latitude, longitude);
                            this.reverseGeocode(latitude, longitude);
                        },
                        (error) => {
                            console.error('Geolocation error:', error);
                            alert('Could not get your location. Please try again or manually position the marker.');
                        },
                        { enableHighAccuracy: true }
                    );
                } else {
                    alert('Geolocation is not supported by your browser');
                }
            }

            tryGetCurrentLocation() {
                if (navigator.geolocation) {
                    navigator.geolocation.getCurrentPosition(
                        (position) => {
                            const latitude = position.coords.latitude;
                            const longitude = position.coords.longitude;
                            this.map.setView([latitude, longitude], 15);
                            this.marker.setLatLng([latitude, longitude]);
                            this.updateLocationData(latitude, longitude);
                            this.reverseGeocode(latitude, longitude);
                        },
                        (error) => {
                            console.error('Geolocation error:', error);
                            // Continue with default location
                        },
                        { enableHighAccuracy: true }
                    );
                }
            }

            updateLocationData(latitude, longitude) {
                this.state.latitude = latitude;
                this.state.longitude = longitude;
                this.state.coordinates = `<i class="fa fa-crosshairs me-1"></i> Lat: ${latitude.toFixed(6)}, Lng: ${longitude.toFixed(6)}`;
                this.state.locationSelected = true;

                // Update hidden form fields
                document.getElementById('latitude').value = latitude;
                document.getElementById('longitude').value = longitude;
            }

            reverseGeocode(latitude, longitude) {
                // Build URL with proper parameters
                const baseUrl = 'https://nominatim.openstreetmap.org/reverse';
                const params = {
                    format: 'json',
                    lat: latitude,
                    lon: longitude,
                    zoom: 18,
                    addressdetails: 1
                };

                // Create URL with parameters
                const url = baseUrl + '?' + Object.entries(params)
                    .map(([key, value]) => key + '=' + value)
                    .join('&');

                fetch(url)
                    .then(response => response.json())
                    .then(data => {
                        if (data && data.display_name) {
                            // Update address in state
                            this.state.address = `<i class="fa fa-map-marker me-2"></i>${data.display_name}`;

                            // Update hidden form field
                            document.getElementById('map_address').value = data.display_name;

                            // Populate address form fields
                            this.populateAddressFields(data);
                        }
                    })
                    .catch(error => {
                        console.error('Reverse geocoding error:', error);
                    });
            }

            populateAddressFields(data) {
                if (!data || !data.address) return;

                const address = data.address;

                // Map Nominatim fields to form fields
                const fieldMappings = {
                    'street': ['road', 'street', 'street_name'],
                    'street2': ['suburb', 'neighbourhood', 'building'],
                    'city': ['city', 'town', 'village', 'county'],
                    'zip': ['postcode'],
                    'state_id': ['state', 'province', 'state_district'],
                    'country_id': ['country', 'country_code']
                };

                // Find form fields
                for (const formField in fieldMappings) {
                    const possibleFields = fieldMappings[formField];

                    // Try to find an input with this name or id
                    let input = document.querySelector(`input[name="${formField}"], #${formField}`);

                    if (input) {
                        // Try each possible field from Nominatim
                        for (let i = 0; i < possibleFields.length; i++) {
                            const nominatimField = possibleFields[i];
                            if (address[nominatimField]) {
                                input.value = address[nominatimField];
                                break;
                            }
                        }
                    }
                }

                // Handle special case for country and state selects
                const countrySelect = document.querySelector('select[name="country_id"]');
                if (countrySelect && address.country_code) {
                    // Find option with matching country code or name
                    const countryCode = address.country_code.toUpperCase();
                    const countryOptions = countrySelect.querySelectorAll('option');

                    for (let i = 0; i < countryOptions.length; i++) {
                        const option = countryOptions[i];
                        if (option.text.includes(countryCode) || 
                            (address.country && option.text.toLowerCase().includes(address.country.toLowerCase()))) {
                            countrySelect.value = option.value;
                            // Trigger change event to update state dropdown
                            countrySelect.dispatchEvent(new Event('change'));
                            break;
                        }
                    }
                }

                // Wait a bit for state dropdown to be populated if country changed
                setTimeout(() => {
                    const stateSelect = document.querySelector('select[name="state_id"]');
                    if (stateSelect && address.state) {
                        const stateOptions = stateSelect.querySelectorAll('option');

                        for (let i = 0; i < stateOptions.length; i++) {
                            const option = stateOptions[i];
                            if (option.text.toLowerCase().includes(address.state.toLowerCase())) {
                                stateSelect.value = option.value;
                                break;
                            }
                        }
                    }
                }, 500);
            }
        }

        // Register and mount the component when DOM is ready
        document.addEventListener('DOMContentLoaded', () => {
            // Mount the component
            const target = document.getElementById('checkout-map-component');
            if (target) {
                const mapComponent = new CheckoutMapComponent();
                mapComponent.mount(target);
            }
        });
})();
